def fibonacci_upto(n: int) -> list[int]:
    """Return a list of Fibonacci numbers less than or equal to n."""
    if n < 0:
        raise ValueError("n must be non‑negative")
    seq = []
    a, b = 0, 1
    while a <= n:
        seq.append(a)
        a, b = b, a + b
    return seq
